{
  "terms": [
    {
      "term": "TT Earthing System",
      "simpleDefinition": "A system where the installation's earth connection is made through a local rod or plate driven into the ground.",
      "anchor": "The 'Terra-Terra' system using a local earth electrode in the garden.",
      "misconception": "Thinking it relies on the supplier's cable for an earth path; it actually relies entirely on the soil."
    },
    {
      "term": "TN-S Earthing System",
      "simpleDefinition": "A system where the supplier provides a completely separate earth conductor all the way back to the transformer.",
      "anchor": "The 'Terre-Neutral-Separate' system with a dedicated earth wire from the street.",
      "misconception": "Confusing it with TN-C-S; in TN-S, the earth and neutral are never the same wire."
    },
    {
      "term": "TN-C-S Earthing System",
      "simpleDefinition": "A system where the neutral and earth are combined in the supply cable but separated at the consumer's intake.",
      "anchor": "The 'Terre-Neutral-Combined-Separate' system, often called PME.",
      "misconception": "Believing the earth and neutral stay combined inside the building; they must be separated at the main cut-out."
    },
    {
      "term": "Circuit Protective Conductor (CPC)",
      "simpleDefinition": "The specific conductor that connects the exposed metal parts of a single circuit to the main earthing terminal.",
      "anchor": "The 'earth wire' found inside a standard circuit cable like Twin and Earth.",
      "misconception": "Calling this the 'Earthing Conductor'; the CPC is only for an individual circuit."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's Main Earth Terminal to the means of earthing (like the supplier's terminal or an electrode).",
      "anchor": "The single heavy-duty green/yellow cable connecting the consumer unit to the earth source.",
      "misconception": "Thinking every green/yellow wire is an earthing conductor; most are actually CPCs or bonding conductors."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal services (like gas or water pipes) to the main earthing terminal to prevent a voltage difference.",
      "anchor": "The safety wires connected to the main incoming gas and water pipes.",
      "misconception": "Thinking these carry fault current from appliances; they are actually there to keep all metalwork at the same potential."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional earth connections between metal parts in high-risk areas, such as bathrooms, to reduce the risk of electric shock.",
      "anchor": "Extra green/yellow links between pipes and metalwork in a shower room.",
      "misconception": "Assuming these are required in every room; they are usually specific to locations with increased shock risk."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component like a circuit breaker or fuse designed to automatically cut off the power during a fault.",
      "anchor": "The MCB or fuse that 'trips' or blows to stop the flow of electricity.",
      "misconception": "Thinking the earth wire itself stops the fault; the earth wire just provides the path so the protective device can trip."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod, plate, or mesh buried in the ground to provide a physical connection to the Earth.",
      "anchor": "The copper-plated rod hammered into the earth for a TT system.",
      "misconception": "Believing every house needs one; they are primarily used when the supplier does not provide an earth terminal."
    }
  ],
  "anchorPhrases": [
    "Local earth rod for TT systems",
    "Separate earth path for TN-S",
    "Combined neutral and earth for TN-C-S",
    "Circuit-specific CPC",
    "Main installation earthing conductor",
    "Bonding for gas and water pipes",
    "Automatic Disconnection of Supply (ADS)"
  ],
  "misconceptionTargets": [
    "The difference between a CPC and the Earthing Conductor",
    "The distinction between TN-S and TN-C-S supply arrangements",
    "The requirement for an earth electrode in TT systems versus TN systems",
    "The role of bonding versus the role of earthing"
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "Earthing systems are identified by a coding system where 'T' stands for Terre (Earth), 'N' for Neutral, 'S' for Separate, and 'C' for Combined. In a TT earthing system, the supplier provides no earth terminal. Instead, the installation relies on a local earth electrode, such as a copper-plated rod driven into the ground, to provide the connection to Earth. This means the 'Terra-Terra' arrangement uses the soil itself as the return path for fault current.",
        "In a TN-S earthing system, the supplier provides a dedicated, separate earth conductor all the way from the transformer to the consumer's intake. This is often the lead sheath or a separate wire within the supply cable. The neutral and earth conductors are never connected together within the installation.",
        "A TN-C-S earthing system uses a single conductor for both neutral and earth in the supplier's street cables (combined), but these are separated into two distinct terminals at the consumer's main cut-out. This arrangement is the most common for new domestic properties and is frequently referred to as Protective Multiple Earthing (PME)."
      ],
      "hint": "Focus on whether the earth and neutral are separate (S) or combined (C) in the supplier's cable, and remember that TT always requires a local rod."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that make up an ADS system.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) relies on several specific components working together to clear a fault safely. The earthing conductor is the heavy-duty green and yellow cable that connects the installation's Main Earth Terminal to the means of earthing, such as the supplier's terminal or an earth electrode. Do not confuse this with the Circuit Protective Conductor (CPC), which is the individual earth wire found within each specific circuit, such as the central wire in a twin and earth cable.",
        "Main protective bonding conductors are used to connect metallic services like incoming gas and water pipes to the main earth terminal. This ensures all accessible metalwork stays at the same potential, reducing shock risk. In high-risk areas like bathrooms, supplementary bonding may be used to link metal parts together locally. Finally, the protective device, such as an MCB or fuse, is the component that actually disconnects the power. It detects the high current flowing through the CPC during a fault and 'trips' or blows to stop the flow of electricity instantly."
      ],
      "hint": "The earthing conductor connects the whole house to the source, while the CPC is only for one circuit. Bonding is for pipes, not circuits."
    }
  ]
}

